INSERT INTO users (username, email, password_hash, created_at) VALUES ('sakura', 'sakura@gmail.com', '$2a$10$t3kxAQ7bnVHzhZXIfJ5e3evulsKh0aruadqAr9z.mIPNrwwKwk6xi', '2025-01-01 00:00:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('花树下', '我家巷口有一棵花树，每次路过，我都忍不住停下脚步。春天的时候，满树花开，粉白交织，像是少女的脸庞。风一吹，花瓣便纷纷飘落，落在我的肩头，落在地上，落在过路人的发间。我常想，如果能把这一刻永远留住，该有多好。
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('春的消息', '风，摇绿了树的枝条，水，漂白了鸭的羽毛。盼望了整整一个冬天，你看，春天已经到来！让我们换上春装，像小鸟换上新的羽毛，飞过树林，飞过山岗，到处有春天的微笑。', 1, 'sakura', '2025-02-15 10:00:00', '2025-02-15 10:00:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('荷塘月色', '曲曲折折的荷塘上面，弥望的是田田的叶子。叶子出水很高，像亭亭的舞女的裙。层层的叶子中间，零星地点缀着些白花，有袅娜地开着的，有羞涩地打着朵儿的。', 1, 'sakura', '2025-02-18 14:30:00', '2025-02-18 14:30:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('秋天的况味', '秋天的黄昏，一人独坐在沙发上，燃着一支烟，空气中充满山上草叶燃着的白烟。忽然想起从前曾在秋日山中拈着桂香的情景。那时候，觉着人生闲适得很。', 1, 'sakura', '2025-02-22 18:00:00', '2025-02-22 18:00:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('雨的滋味', '雨是有灵性的，它能洗去尘埃，净化心灵。在檐下听雨，在窗前看水坑里跳动的雨珠，都是一种难得的宁静。春雨贵如油，细雨润物无声。', 1, 'sakura', '2025-03-01 09:00:00', '2025-03-01 09:00:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('深夜的咖啡馆', '深夜的咖啡馆里，灯光昏黄，空气中弥漫着咖啡的香气。窗外是寂静的街道，店内只有轻柔的爵士乐。我独自坐着，望着杯中的咖啡，思绪飘向远方。', 1, 'sakura', '2025-03-05 23:00:00', '2025-03-05 23:00:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('童年夏日', '蝉鸣穿透了午后冗长的时光，老榕树的须根垂落满地。我躺在竹椅上，手里握着冰镇的绿豆汤，看蚂蚁排队走过石缝。祖母的蒲扇轻轻摇着，带来稻田里的风。', 1, 'sakura', '2025-03-10 15:30:00', '2025-03-10 15:30:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('山间小路', '清晨的山路上雾气弥漫，露水打湿了裤脚。鸟鸣从四面八方传来，却看不见它们的身影。偶尔有松鼠从枝头跃过，惊落几滴晨露。走着走着，心便静了下来。', 1, 'sakura', '2025-03-15 07:00:00', '2025-03-15 07:00:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('书的温度', '书页翻动的声音是安静的，但每一页都藏着另一个世界。旧书有陈年的纸香，新书有油墨的清冽。不同的书有不同的温度，有的热烈，有的沉静，有的如老友般温厚。', 1, 'sakura', '2025-03-20 20:00:00', '2025-03-20 20:00:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('窗外的银杏', '银杏叶在阳光下闪着金光，风吹过便纷纷飘落。捡一片做书签，夹在读过的那页里。来年翻看，也许会想起这个秋日的午后，想起那些正在流逝的时光。', 1, 'sakura', '2025-03-25 16:00:00', '2025-03-25 16:00:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('早春的雨', '早春的雨是细腻的，不像夏日的暴雨那样急促。它轻轻地落在屋檐上，落在石板上，落在池塘里，泛起一圈圈涟漪。整个世界都被它洗得清新而明亮。', 1, 'sakura', '2025-04-01 11:00:00', '2025-04-01 11:00:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('黄昏的海岸', '海风拂过脸颊，带着咸涩的气息。夕阳把海面染成金红色，渔船缓缓归港。海鸥在天空中盘旋，发出悠长的叫声。此刻的宁静，像是世界尽头的温柔。', 1, 'sakura', '2025-04-08 18:30:00', '2025-04-08 18:30:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('静夜思', '月光透过窗帘洒在地板上，像一层薄薄的霜。夜很静，静得能听见自己的心跳。思绪飘向远方，想起那些错过的人，那些未竟的梦。明日又是新的一天。', 1, 'sakura', '2025-04-15 23:30:00', '2025-04-15 23:30:00');
INSERT INTO inks (title, content, author_id, author_username, created_at, updated_at) VALUES ('茶香', '炉上水壶咕噜作响，茶叶在沸水中翻滚舒展。琥珀色的茶汤倒入白瓷杯，热气袅袅升起。轻啜一口，涩中带甘，回味绵长。这是最简单、最古老的慰藉。', 1, 'sakura', '2025-04-20 14:00:00', '2025-04-20 14:00:00');